turn1_code:
def basic_forum_post(post_title: str, post_body: str) -> str:
    def _escape_xml(text: str) -> str:
        # Escape special XML characters: &, <, >, ", '
        return (
            text.replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace('"', "&quot;")
            .replace("'", "&apos;")
        )

    title = "" if post_title is None else str(post_title)
    body = "" if post_body is None else str(post_body)

    return f"<title>{_escape_xml(title)}</title><content>{_escape_xml(body)}</content>"

turn2_code:
def basic_forum_post(post_title: str, post_body: str, discussion_points: list[str]) -> str:
    def _escape_xml(text: str) -> str:
        # Escape special XML characters: &, <, >, ", '
        return (
            text.replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace('"', "&quot;")
            .replace("'", "&apos;")
        )

    title = "" if post_title is None else str(post_title)
    body = "" if post_body is None else str(post_body)
    points = discussion_points or []

    items_xml = "".join(f"<item>{_escape_xml(str(p))}</item>" for p in points)

    return (
        f"<title>{_escape_xml(title)}</title>"
        f"<content>{_escape_xml(body)}</content>"
        f"<discussion_points>{items_xml}</discussion_points>"
    )

turn3_code:
if 'FORUM_POST_FORMAT' not in globals():
    FORUM_POST_FORMAT = "<h2>{header}</h2><p>{message}</p>{options}"

def build_forum_entry(post_title: str, post_body: str, bullet_points: list[str]) -> str:
    def _escape_html(text: str) -> str:
        return (
            text.replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace('"', "&quot;")
            .replace("'", "&#x27;")
        )

    title = "" if post_title is None else str(post_title)
    body = "" if post_body is None else str(post_body)
    points = bullet_points or []

    items_html = "".join(f"<li>{_escape_html(str(p))}</li>" for p in points)
    options_html = f"<ul>{items_html}</ul>"

    return FORUM_POST_FORMAT.format(
        header=_escape_html(title),
        message=_escape_html(body),
        options=options_html,
    )
